// Activate the set / map axioms locally so `is_full()` (which unfolds to
// `self == Set::empty().complement()`) actually gives a usable
// `dom() =~= Set::full()`, and `axiom_map_ext_equal` is in scope to lift
// pointwise equality + domain equality to `post1@ =~= post2@`. Without
// `group_set_axioms` Verus could not discharge the previous attempt's
// `assert(post1_self_@.dom() =~= post2_self_@.dom())`.
broadcast use vstd::set::group_set_axioms;
broadcast use vstd::map::group_map_axioms;

// The ensures of `det_set` is `antecedent ==> det_set_equal(...)`. Wrap
// the proof in `if antecedent { ... }` so the two runs' per-key forall
// ensures become local hypotheses with aligned triggers; after the
// branch Verus has `antecedent ==> post1_self_@ =~= post2_self_@`,
// which is exactly the implication ensures demands (det_set_equal's
// only non-trivial conjunct is `(post1_self_).view() == (post2_self_).view()`).
if post1_self_.valid()
    && (forall |ki:KeyIterator<K>| #[trigger] KeyIterator::between(*lo, ki, *hi) ==> post1_self_@[*ki.get()] == dst@)
    && (forall |ki:KeyIterator<K>| !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi)) ==> post1_self_@[*ki.get()] == pre_self_@[*ki.get()])
    && post2_self_.valid()
    && (forall |ki:KeyIterator<K>| #[trigger] KeyIterator::between(*lo, ki, *hi) ==> post2_self_@[*ki.get()] == dst@)
    && (forall |ki:KeyIterator<K>| !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi)) ==> post2_self_@[*ki.get()] == pre_self_@[*ki.get()])
{
    // `valid()` implies `dom().is_full()`; with `group_set_axioms`
    // broadcast, Verus can read this as `dom() =~= Set::<K>::full()`
    // (i.e. `dom().contains(k) == true` for every k:K).
    post1_self_.valid_implies_complete();
    post2_self_.valid_implies_complete();

    // Both domains equal `Set::<K>::full()` pointwise, hence equal each
    // other. The intermediate `=~= Set::<K>::full()` step pins
    // `dom().contains(k)` down to `Set::full().contains(k) == true` via
    // `axiom_set_complement`/`axiom_set_empty`/`axiom_set_ext_equal`.
    assert(post1_self_@.dom() =~= Set::<K>::full());
    assert(post2_self_@.dom() =~= Set::<K>::full());
    assert(post1_self_@.dom() =~= post2_self_@.dom());

    // Pointwise equality on the view: for every k:K, build the non-end
    // iterator `ki = KeyIterator::new_spec(k)` (so `*ki.get() == k` and
    // `!ki.is_end_spec()`), then case-split on
    // `KeyIterator::between(*lo, ki, *hi)`. In each branch the
    // corresponding `forall` ensures fires (its trigger is exactly the
    // case-split term), pinning both post-views at k to the same value
    // (`dst@` in the `between` branch, `pre_self_@[k]` otherwise).
    assert forall |k: K| post1_self_@[k] == post2_self_@[k] by {
        let ki: KeyIterator<K> = KeyIterator::<K>::new_spec(k);
        assert(!ki.is_end_spec());
        assert(*ki.get() == k);
        if KeyIterator::between(*lo, ki, *hi) {
            assert(post1_self_@[*ki.get()] == dst@);
            assert(post2_self_@[*ki.get()] == dst@);
            assert(post1_self_@[k] == dst@);
            assert(post2_self_@[k] == dst@);
        } else {
            assert(post1_self_@[*ki.get()] == pre_self_@[*ki.get()]);
            assert(post2_self_@[*ki.get()] == pre_self_@[*ki.get()]);
            assert(post1_self_@[k] == pre_self_@[k]);
            assert(post2_self_@[k] == pre_self_@[k]);
        }
    }

    // Map extensionality (`axiom_map_ext_equal`, now broadcast): with
    // identical full domain + pointwise-on-domain equality, the two
    // views are `=~=`.
    assert(post1_self_@ =~= post2_self_@);
}
